app.put("/api/auth/profile", (req, res) => {
  const authUser = getAuthUser(req);
  if (!authUser) {
    return res.status(401).json({ success: false, error: { code: "UNAUTHORIZED", message: "غير مصرح بالدخول" } });
  }

  try {
    const db = readDB();
    const userIndex = db.users.findIndex((u: UserProfile) => u.uid === authUser.uid);
    if (userIndex === -1) {
      return res.status(404).json({ success: false, error: { code: "NOT_FOUND", message: "المستخدم غير موجود" } });
    }

    const allowedKeys = ["username", "subscriptionStatus", "pendingSubscriptionType", "paymentTxInfo"];
    const updates: any = {};
    
    for (const key of allowedKeys) {
      if (req.body[key] !== undefined) {
        if (key === "subscriptionStatus") {
          const val = req.body[key];
          if (val === "pending" || val === "none") {
            updates[key] = val;
          }
        } else if (key === "pendingSubscriptionType") {
          const val = req.body[key];
          if (val === "none" || val === "bronze" || val === "gold") {
            updates[key] = val;
          }
        } else {
          updates[key] = req.body[key];
        }
      }
    }

    db.users[userIndex] = {
      ...db.users[userIndex],
      ...updates
    };
    writeDB(db);

    res.json({ success: true, profile: db.users[userIndex], data: { profile: db.users[userIndex] } });
  } catch (err: any) {
    res.status(500).json({ success: false, error: { code: "INTERNAL_ERROR", message: err.message } });
  }
});

