// GET /api/local-files/check
app.get("/api/local-files/check", (req, res) => {
  const filePath = req.query.path as string;
  if (!filePath) {
    return res.json({ exists: false, readable: false, error: "لم يتم تحديد مسار الملف" });
  }
  try {
    const normalizedPath = path.normalize(filePath);
    const existsReal = fs.existsSync(normalizedPath) && fs.statSync(normalizedPath).isFile();
    let readableReal = false;
    let accessErrorMsg = null;
    let errorCode = null;

    if (existsReal) {
      try {
        fs.accessSync(normalizedPath, fs.constants.R_OK);
        readableReal = true;
      } catch (accessErr: any) {
        readableReal = false;
        errorCode = accessErr.code || "EACCES";
        accessErrorMsg = `تعذر قراءة الملف بسبب قيود الوصول أو الصلاحيات البرمجية للنظام (${accessErr.code})`;
      }
    } else {
      errorCode = "ENOENT";
      accessErrorMsg = "الملف غير موجود في المسار المحدد على القرص الصلب";
    }

    res.json({ 
      exists: existsReal,
      readable: readableReal,
      error: accessErrorMsg,
      errorCode: errorCode,
      simulated: false 
    });
  } catch (err: any) {
    res.json({ exists: false, readable: false, error: err.message, simulated: false });
  }
});

