// GET /api/local-media/view
app.get("/api/local-media/view", (req, res) => {
  const lectureId = req.query.lectureId as string;
  const token = req.query.token as string;

  if (!lectureId || !token) {
    return res.status(401).send("Unauthorized");
  }

  const verified = verifyMediaToken(token, 'download');
  if (!verified || verified.lectureId !== lectureId) {
    return res.status(403).send("Forbidden");
  }

  try {
    const db = readDB();
    const lecture = db.lectures.find((l: Lecture) => l.id === lectureId);
    if (!lecture || !lecture.fileUrl) return res.status(404).send("File not found");

    let filePath = lecture.fileUrl;
    if (!path.isAbsolute(filePath)) {
      filePath = path.join(process.cwd(), filePath.startsWith('/') ? filePath.substring(1) : filePath);
    }

    if (!fs.existsSync(filePath) || !isPathAllowed(filePath)) {
      const folders = db.settings.mediaFolders && db.settings.mediaFolders.length > 0 
        ? db.settings.mediaFolders 
        : [STORAGE_DIR];
      const found = smartSearchFile(folders, lecture.fileName || path.basename(filePath));
      if (found && isPathAllowed(found)) {
        filePath = found;
      } else {
        return res.status(404).send("File not found");
      }
    }

    const utf8Filename = encodeURIComponent(lecture.fileName || path.basename(filePath));
    res.setHeader('Content-Type', getContentType(filePath));
    res.setHeader('Content-Disposition', `inline; filename="${path.basename(filePath)}"; filename*=UTF-8''${utf8Filename}`);
    fs.createReadStream(filePath).pipe(res);
  } catch (err: any) {
    res.status(500).send("Error reading file: " + err.message);
  }
});

// GET /api/media/stream/:lectureId (Fallback compatibility stream)
app.get("/api/media/stream/:lectureId", (req, res) => {
  const { lectureId } = req.params;
  const token = req.query.token as string || req.headers.authorization?.split(" ")[1];

  let userUid: string | null = null;
  if (token) {
    const verified = verifyMediaToken(token, 'stream');
    if (verified && verified.lectureId === lectureId) {
      userUid = verified.uid;
    } else {
      userUid = verifyToken(token);
    }
  }

  if (!userUid) {
    const authUser = getAuthUser(req);
    if (authUser) userUid = authUser.uid;
  }

  try {
    const db = readDB();
    const lecture = db.lectures.find((l: Lecture) => l.id === lectureId);
    if (!lecture) return res.status(404).json({ error: "Lecture not found" });

    if (lecture.tierRequired && lecture.tierRequired !== 'free') {
      if (!userUid) {
        return res.status(401).json({ error: "غير مصرح. يرجى تسجيل الدخول أو توفير رمز المرور للبث." });
      }
      const user = db.users.find((u: UserProfile) => u.uid === userUid);
      const access = checkLectureAccess(user || null, lecture);
      if (!access.hasAccess) {
        return res.status(403).json({ error: access.error || "مرفوض" });
      }
    }

    let videoPath = lecture.videoUrl;
    if (!path.isAbsolute(videoPath)) {
      videoPath = path.join(process.cwd(), videoPath.startsWith('/') ? videoPath.substring(1) : videoPath);
    }

    if (!fs.existsSync(videoPath) || !isPathAllowed(videoPath)) {
      const folders = db.settings.mediaFolders && db.settings.mediaFolders.length > 0 
        ? db.settings.mediaFolders 
        : [STORAGE_DIR];
      
      const found = smartSearchFile(folders, lecture.videoFileName || path.basename(videoPath), lecture.videoSize);
      if (found && isPathAllowed(found)) {
        videoPath = found;
      } else {
        return res.status(404).json({ error: "File not found" });
      }
    }

    streamMedia(req, res, videoPath);
  } catch (err: any) {
    res.status(500).json({ error: err.message });
  }
});

