import fs from "fs";
import path from "path";
import { ZipArchive } from "archiver";

const DATA_DIR = path.join(process.cwd(), "data");
const BACKUP_DIR = path.join(DATA_DIR, "backups");
const DB_FILE = path.join(DATA_DIR, "db.json");
const MAX_BACKUPS = 10;

export async function createBackup(): Promise<string> {
  if (!fs.existsSync(BACKUP_DIR)) fs.mkdirSync(BACKUP_DIR, { recursive: true });

  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
  const backupFileName = `backup-${timestamp}.zip`;
  const backupFilePath = path.join(BACKUP_DIR, backupFileName);

  const output = fs.createWriteStream(backupFilePath);
  const archive = new ZipArchive({ zlib: { level: 9 } });

  return new Promise((resolve, reject) => {
    output.on("close", () => {
      maintainBackupRotation();
      resolve(backupFileName);
    });
    archive.on("error", reject);
    archive.pipe(output);
    archive.file(DB_FILE, { name: "db.json" });
    archive.finalize();
  });
}

function maintainBackupRotation() {
  const files = fs.readdirSync(BACKUP_DIR)
    .filter(f => f.startsWith("backup-") && f.endsWith(".zip"))
    .map(f => ({ name: f, time: fs.statSync(path.join(BACKUP_DIR, f)).mtime.getTime() }))
    .sort((a, b) => b.time - a.time);

  if (files.length > MAX_BACKUPS) {
    files.slice(MAX_BACKUPS).forEach(f => fs.unlinkSync(path.join(BACKUP_DIR, f.name)));
  }
}

export function restoreBackup(backupFileName: string) {
  const backupFilePath = path.join(BACKUP_DIR, backupFileName);
  if (!fs.existsSync(backupFilePath)) throw new Error("ملف النسخة الاحتياطية غير موجود");
  
  // Basic integrity check could be adding a checksum, but for now just check existence
  fs.copyFileSync(backupFilePath, DB_FILE);
}
